import{_ as o}from"./plugin-vue_export-helper-c27b6911.js";import{r as n,o as l,c as s,b as r,a,e,w as h,d as i}from"./app-75fed8c6.js";const c={},p=a("h2",{id:"meshnormalmaterial",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#meshnormalmaterial","aria-hidden":"true"},"#"),e(" MeshNormalMaterial")],-1),m=a("p",null,"一种把法向量映射到RGB颜色的材质。",-1),f=i('<h2 id="构造器" tabindex="-1"><a class="header-anchor" href="#构造器" aria-hidden="true">#</a> 构造器</h2><h3 id="parameters-object" tabindex="-1"><a class="header-anchor" href="#parameters-object" aria-hidden="true">#</a> parameters : Object</h3><p>parameters - (可选)用于定义材质外观的对象，具有一个或多个属性。材质的任何属性都可以从此处传入(包括从Material继承的任何属性)</p><h2 id="属性" tabindex="-1"><a class="header-anchor" href="#属性" aria-hidden="true">#</a> 属性</h2>',4),u=i('<h3 id="bumpmap-texture" tabindex="-1"><a class="header-anchor" href="#bumpmap-texture" aria-hidden="true">#</a> .bumpMap : Texture</h3><p>用于创建凹凸贴图的纹理。黑色和白色值映射到与光照相关的感知深度。凹凸实际上不会影响对象的几何形状，只影响光照。如果定义了法线贴图，则将忽略该贴图。</p><h3 id="bumpscale-float" tabindex="-1"><a class="header-anchor" href="#bumpscale-float" aria-hidden="true">#</a> .bumpScale : Float</h3><p>凹凸贴图会对材质产生多大影响。典型范围是0-1。默认值为1。</p><h3 id="displacementmap-texture" tabindex="-1"><a class="header-anchor" href="#displacementmap-texture" aria-hidden="true">#</a> .displacementMap : Texture</h3><p>位移贴图会影响网格顶点的位置，与仅影响材质的光照和阴影的其他贴图不同，移位的顶点可以投射阴影，阻挡其他对象， 以及充当真实的几何体。位移纹理是指：网格的所有顶点被映射为图像中每个像素的值（白色是最高的），并且被重定位。</p><h3 id="displacementscale-float" tabindex="-1"><a class="header-anchor" href="#displacementscale-float" aria-hidden="true">#</a> .displacementScale : Float</h3><p>位移贴图对网格的影响程度（黑色是无位移，白色是最大位移）。如果没有设置位移贴图，则不会应用此值。默认值为1。</p><h3 id="displacementbias-float" tabindex="-1"><a class="header-anchor" href="#displacementbias-float" aria-hidden="true">#</a> .displacementBias : Float</h3><p>位移贴图在网格顶点上的偏移量。如果没有设置位移贴图，则不会应用此值。默认值为0。</p><h3 id="flatshading-boolean" tabindex="-1"><a class="header-anchor" href="#flatshading-boolean" aria-hidden="true">#</a> .flatShading : Boolean</h3><p>定义材质是否使用平面着色进行渲染。默认值为false。</p><h3 id="normalmap-texture" tabindex="-1"><a class="header-anchor" href="#normalmap-texture" aria-hidden="true">#</a> .normalMap : Texture</h3><p>用于创建法线贴图的纹理。RGB值会影响每个像素片段的曲面法线，并更改颜色照亮的方式。法线贴图不会改变曲面的实际形状，只会改变光照。 In case the material has a normal map authored using the left handed convention, the y component of normalScale should be negated to compensate for the different handedness.</p><h3 id="normalmaptype-integer" tabindex="-1"><a class="header-anchor" href="#normalmaptype-integer" aria-hidden="true">#</a> .normalMapType : Integer</h3><p>法线贴图的类型。</p><p>选项为THREE.TangentSpaceNormalMap（默认）和THREE.ObjectSpaceNormalMap。</p><h3 id="normalscale-vector2" tabindex="-1"><a class="header-anchor" href="#normalscale-vector2" aria-hidden="true">#</a> .normalScale : Vector2</h3><p>法线贴图对材质的影响程度。典型范围是0-1。默认值是Vector2设置为（1,1）。</p><h3 id="wireframe-boolean" tabindex="-1"><a class="header-anchor" href="#wireframe-boolean" aria-hidden="true">#</a> .wireframe : Boolean</h3><p>将几何体渲染为线框。默认值为false（即渲染为平滑着色）。</p><h3 id="wireframelinewidth-float" tabindex="-1"><a class="header-anchor" href="#wireframelinewidth-float" aria-hidden="true">#</a> .wireframeLinewidth : Float</h3><p>控制线框宽度。默认值为1。</p><p>由于OpenGL Core Profile与大多数平台上WebGL渲染器的限制，无论如何设置该值，线宽始终为1。</p><h2 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h2>',25);function b(_,x){const d=n("IFrame"),t=n("RouterLink");return l(),s("div",null,[p,m,r(d,{url:"https://luotainxu-demo.netlify.app/#/threejs/material/meshNormalMaterial"}),f,a("p",null,[e("共有属性请参见其基类"),r(t,{to:"/threejs/%E6%9D%90%E8%B4%A8/%E6%9D%90%E8%B4%A8.html"},{default:h(()=>[e("Material")]),_:1})]),u,a("p",null,[e("共有方法请参见其基类"),r(t,{to:"/threejs/%E6%9D%90%E8%B4%A8/%E6%9D%90%E8%B4%A8.html"},{default:h(()=>[e("Material")]),_:1})])])}const M=o(c,[["render",b],["__file","法线网格材质.html.vue"]]);export{M as default};
